+
+    __aicore__ inline Buffer<bufferType, syncType> &Get(){
+        return buffer_;
+    }
+
+    __aicore__ inline Buffer<bufferType, syncType> &GetPre(){
+        return Get();
+    }
+
+    __aicore__ inline Buffer<bufferType, syncType> &GetReused(){
