+                                                                            vreg0U16, inputBuf + i * 256);
+        MicroAPI::LoadAlign<uint32_t, MicroAPI::LoadDist::DIST_DINTLV_B16>(vreg3U16,
+                                                                            vreg2U16, inputBuf + (i * 256) + 128);
