+    // Create query aclTensor.
+    int32_t ret = CreateAclTensor(queryHostData, queryShape, &resources.queryDeviceAddr, 
+                             aclDataType::ACL_FLOAT16, &resources.queryTensor);
+    if (!CHECK_RET(ret == ACL_SUCCESS)) {
